INSERT INTO messages (channel_id, subject_channel_id, user_id, content, created_at) VALUES
(1, 1, 2, 'Добро пожаловать на курс Математика! Занятия начинаются в понедельник в 9:00. Не забудьте взять учебник.', NOW() - INTERVAL '3 days'),
(1, 1, 3, 'Уважаемые студенты, напоминаю: контрольная работа по теме "Производные" пройдёт в пятницу. Повторите материалы с 1 по 5 параграф.', NOW() - INTERVAL '2 days'),
(1, 1, 2, 'Загрузила конспект лекции №3 в раздел "Материалы". Скачайте до следующего занятия!', NOW() - INTERVAL '1 day'),
(1, 5, 4, 'Мария Владимировна, подскажите — задание на следующую неделю включает 3-ю главу?', NOW() - INTERVAL '2 days' + INTERVAL '1 hour'),
(1, 5, 2, 'Иван, да, 3-я глава входит. Также рекомендую задачи из Сборника Демидовича стр. 45-52.', NOW() - INTERVAL '2 days' + INTERVAL '2 hours'),
(1, 5, 5, 'Всем привет! Кто уже решил домашнее задание? Застряла на задаче №7 😅', NOW() - INTERVAL '1 day' + INTERVAL '3 hours'),
(1, 5, 6, 'Анна, я тоже! Попробуй через замену переменной, мне помогло)', NOW() - INTERVAL '1 day' + INTERVAL '4 hours'),
(1, 5, 4, 'Спасибо за подсказку, Дима! Разобрался в итоге 👍', NOW() - INTERVAL '1 day' + INTERVAL '5 hours'),
(1, 5, 2, 'Молодцы, что помогаете друг другу! Это именно то, что нужно 🎓', NOW() - INTERVAL '20 hours'),
(1, 3, 2, 'Домашнее задание: Демидович §4, задачи 1-20. Срок сдачи — воскресенье 23:59.', NOW() - INTERVAL '4 days'),
(1, 3, 4, 'Мария Владимировна, можно сдать в понедельник утром? У меня соревнования.', NOW() - INTERVAL '3 days'),
(1, 3, 2, 'Иван, хорошо, сдайте до 10:00 в понедельник.', NOW() - INTERVAL '3 days' + INTERVAL '1 hour'),
(1, 3, 5, 'Подскажите, задача 15 — интеграл по частям или подстановка?', NOW() - INTERVAL '2 days'),
(1, 3, 3, 'Анна, там удобнее подстановка. Сделайте u = x²+1', NOW() - INTERVAL '2 days' + INTERVAL '30 minutes'),
(1, 10, 3, 'Привет! На следующем занятии разбираем алгоритмы сортировки. Погуглите "bubble sort" и "quick sort".', NOW() - INTERVAL '5 days'),
(1, 10, 4, 'Алексей Николаевич, практика будет на Python или любом языке?', NOW() - INTERVAL '5 days' + INTERVAL '2 hours'),
(1, 10, 3, 'Иван, предпочтительно Python, но принимаю и C++. Главное — работающий код с комментариями.', NOW() - INTERVAL '5 days' + INTERVAL '3 hours'),
(1, 10, 6, 'Запилил быструю сортировку на Python, 50 строк. Показать на следующей паре?', NOW() - INTERVAL '4 days'),
(1, 10, 3, 'Дмитрий, отлично! Да, покажи — разберём вместе.', NOW() - INTERVAL '4 days' + INTERVAL '1 hour'),
(1, 10, 5, 'Рекурсию обязательно использовать в quick sort или можно итеративно?', NOW() - INTERVAL '3 days'),
(1, 10, 3, 'Можно итеративно через стек. Но рекурсия — классика, лучше разобраться 😉', NOW() - INTERVAL '3 days' + INTERVAL '1 hour'),
(1, 9, 5, 'Алексей Николаевич, у меня ошибка IndexError при запуске сортировки 😢', NOW() - INTERVAL '2 days'),
(1, 9, 3, 'Анна, пришлите код — посмотрю. Скорее всего выход за границы массива.', NOW() - INTERVAL '2 days' + INTERVAL '30 minutes'),
(1, 9, 4, 'У меня похожая была — проверь что цикл до len(arr)-1, а не len(arr)', NOW() - INTERVAL '2 days' + INTERVAL '1 hour'),
(1, 9, 5, 'Иван, точно! Спасибо, заработало! 🎉', NOW() - INTERVAL '2 days' + INTERVAL '2 hours');
